(window.webpackJsonp=window.webpackJsonp||[]).push([[425],{1052:function(n,r){n.exports='\x3c!-- \r\ntitle: 05-H5新增\r\nsort: \r\n--\x3e \r\n# HTML5新增标签\r\n\r\n## Input\r\n\r\n> 拥有多个表单输入类型\r\n\r\n```html\r\n选择你喜欢的颜色: <input type="color" name="favcolor">\r\n生日: <input type="date" name="bday">\r\n生日 (日期和时间): <input type="datetime-local" name="bdaytime">\r\nE-mail: <input type="email" name="email">\r\n生日 (月和年): <input type="month" name="bdaymonth">\r\n数量 ( 1 到 5 之间 ): <input type="number" name="quantity" min="1" max="5">\r\n滑块选择：<input type="range" name="points" min="1" max="10">\r\nSearch Google: <input type="search" name="googlesearch">\r\n电话号码: <input type="tel" name="usrtel">\r\n选择时间: <input type="time" name="usr_time">\r\n添加您的主页: <input type="url" name="homepage">\r\n选择周: <input type="week" name="week_year">\r\n```\r\n\r\n## Form\r\n\r\n> 新的表单\r\n\r\n### datalist\r\n\r\n> 输入域的选项列表\r\n\r\n```html\r\n<form action="form.php" method="get">\r\n<input list="browsers" name="browser">\r\n<datalist id="browsers">\r\n  <option value="Internet Explorer">\r\n  <option value="Firefox">\r\n  <option value="Chrome">\r\n  <option value="Opera">\r\n  <option value="Safari">\r\n</datalist>\r\n<input type="submit">\r\n</form>\r\n```\r\n\r\n### keygen\r\n\r\n> 验证用户的可靠方法\r\n\r\n```html\r\n<form action="demo_keygen.asp" method="get">\r\n用户名: <input type="text" name="usr_name">\r\n加密: <keygen name="security">\r\n<input type="submit">\r\n</form>\r\n```\r\n\r\n## Web 存储\r\n\r\n```html\r\n<!DOCTYPE html>\r\n<html>  \r\n<head>  \r\n    <meta charset="utf-8">  \r\n    <title>HTML5本地存储之Web Storage篇</title>  \r\n</head>  \r\n<body>  \r\n    <div style="border: 2px dashed #ccc;width:320px;text-align:center;">     \r\n        <label for="sitename">网站名(key)：</label>  \r\n        <input type="text" id="sitename" name="sitename" class="text"/>  \r\n        <br/>  \r\n        <label for="siteurl">网 址(value)：</label>  \r\n        <input type="text" id="siteurl" name="siteurl"/>  \r\n        <br/>  \r\n        <input type="button" onclick="save()" value="新增记录"/>  \r\n        <hr/>  \r\n        <label for="search_phone">输入网站名：</label>  \r\n        <input type="text" id="search_site" name="search_site"/>  \r\n        <input type="button" onclick="find()" value="查找网站"/>  \r\n        <p id="find_result"><br/></p>  \r\n    </div>  \r\n    <br/>  \r\n    <div id="list">  \r\n    </div>  \r\n    <script>\r\n\t// 载入所有存储在localStorage的数据\r\n\tloadAll(); \t\r\n\t\t\r\n    //保存数据  \r\n    function save(){  \r\n        var siteurl = document.getElementById("siteurl").value;  \r\n        var sitename = document.getElementById("sitename").value;  \r\n        localStorage.setItem(sitename, siteurl);\r\n        alert("添加成功");\r\n    }\r\n    //查找数据  \r\n    function find(){  \r\n        var search_site = document.getElementById("search_site").value;  \r\n        var siteurl = localStorage.getItem(search_site);  \r\n        var find_result = document.getElementById("find_result");  \r\n        find_result.innerHTML = search_site + "的网址是：" + siteurl;  \r\n    }\r\n    //将所有存储在localStorage中的对象提取出来，并展现到界面上\r\n    function loadAll(){  \r\n        var list = document.getElementById("list");  \r\n        if(localStorage.length>0){  \r\n            var result = "<table border=\'1\'>";  \r\n            result += "<tr><td>key</td><td>value</td></tr>";  \r\n            for(var i=0;i<localStorage.length;i++){  \r\n                var sitename = localStorage.key(i);  \r\n                var siteurl = localStorage.getItem(sitename);  \r\n                result += "<tr><td>"+sitename+"</td><td>"+siteurl+"</td></tr>";  \r\n            }  \r\n            result += "</table>";  \r\n            list.innerHTML = result;  \r\n        }else{  \r\n            list.innerHTML = "数据为空……";  \r\n        }  \r\n    }      \r\n    <\/script>\r\n</body>  \r\n</html>\r\n```\r\n\r\n'}}]);